import React, { useState, useEffect, useCallback } from 'react';
import { puzzles } from './data/puzzles.js';
import { bridgeKey, canAddBridge, isVictory } from './utils/hashiLogic.js';

const GRID = 40;

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(0);
  const [errorMsg, setErrorMsg] = useState(null);
  const [victory, setVictory] = useState(false);

  const puzzle = puzzles[puzzleIndex];
  const islands = puzzle.islands;

  // Reset everything when puzzle changes
  const resetPuzzle = useCallback(() => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMsg(null);
    setVictory(false);
  }, []);

  const handlePuzzleChange = (e) => {
    setPuzzleIndex(Number(e.target.value));
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMsg(null);
    setVictory(false);
  };

  const handleReset = () => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMsg(null);
    setVictory(false);
  };

  // Toggle bridge between two islands: none -> single -> double -> none
  const toggleBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const currentCount = bridges.get(key) || 0;

    if (currentCount === 0) {
      // Try to add single
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setErrorMsg(result.error);
        return;
      }
      const newBridges = new Map(bridges);
      newBridges.set(key, 1);
      setErrorMsg(null);
      setBridges(newBridges);
      const won = isVictory(islands, newBridges);
      setVictory(won);
    } else if (currentCount === 1) {
      // Try to add second
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setErrorMsg(result.error);
        return;
      }
      const newBridges = new Map(bridges);
      newBridges.set(key, 2);
      setErrorMsg(null);
      setBridges(newBridges);
      const won = isVictory(islands, newBridges);
      setVictory(won);
    } else {
      // Remove (double -> none)
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setErrorMsg(null);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges, islands]);

  // Remove bridge entirely
  const removeBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const currentCount = bridges.get(key) || 0;
    if (currentCount > 0) {
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setErrorMsg(null);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges]);

  // Handle island click
  const handleIslandClick = useCallback((island, e) => {
    if (e.ctrlKey || e.button === 2) {
      // Right-click or ctrl-click: remove bridge if selected
      if (selectedIsland !== null && selectedIsland.id !== island.id) {
        removeBridge(selectedIsland, island);
        setSelectedIsland(null);
      } else if (selectedIsland === null) {
        // If clicking with ctrl/right on unselected, select it for removal mode
        setSelectedIsland(island);
        setCursorIslandId(island.id);
      }
      return;
    }

    if (selectedIsland === null) {
      setSelectedIsland(island);
      setCursorIslandId(island.id);
      setErrorMsg(null);
    } else if (selectedIsland.id === island.id) {
      setSelectedIsland(null);
    } else {
      toggleBridge(selectedIsland, island);
      setSelectedIsland(null);
    }
  }, [selectedIsland, toggleBridge, removeBridge]);

  // Handle right-click on island
  const handleIslandRightClick = useCallback((island, e) => {
    e.preventDefault();
    if (selectedIsland !== null && selectedIsland.id !== island.id) {
      removeBridge(selectedIsland, island);
      setSelectedIsland(null);
    } else {
      setSelectedIsland(island);
      setCursorIslandId(island.id);
    }
  }, [selectedIsland, removeBridge]);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      const currentIsland = islands.find(i => i.id === cursorIslandId);
      if (!currentIsland) return;

      if (e.key === 'Escape') {
        setSelectedIsland(null);
        setErrorMsg(null);
        return;
      }

      if (e.key === 'Enter') {
        if (selectedIsland === null) {
          setSelectedIsland(currentIsland);
          setErrorMsg(null);
        } else if (selectedIsland.id === currentIsland.id) {
          setSelectedIsland(null);
        } else {
          toggleBridge(selectedIsland, currentIsland);
          setSelectedIsland(null);
        }
        return;
      }

      if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
        e.preventDefault();
        let nextIsland = null;
        let bestDist = Infinity;

        for (const island of islands) {
          if (island.id === currentIsland.id) continue;

          let valid = false;
          let dist = 0;

          if (e.key === 'ArrowRight' && island.x > currentIsland.x) {
            dist = Math.abs(island.x - currentIsland.x) + Math.abs(island.y - currentIsland.y) * 0.01;
            valid = true;
          } else if (e.key === 'ArrowLeft' && island.x < currentIsland.x) {
            dist = Math.abs(island.x - currentIsland.x) + Math.abs(island.y - currentIsland.y) * 0.01;
            valid = true;
          } else if (e.key === 'ArrowDown' && island.y > currentIsland.y) {
            dist = Math.abs(island.y - currentIsland.y) + Math.abs(island.x - currentIsland.x) * 0.01;
            valid = true;
          } else if (e.key === 'ArrowUp' && island.y < currentIsland.y) {
            dist = Math.abs(island.y - currentIsland.y) + Math.abs(island.x - currentIsland.x) * 0.01;
            valid = true;
          }

          if (valid && dist < bestDist) {
            bestDist = dist;
            nextIsland = island;
          }
        }

        if (nextIsland) {
          setCursorIslandId(nextIsland.id);
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [cursorIslandId, selectedIsland, islands, toggleBridge]);

  // Prevent context menu
  useEffect(() => {
    const handler = (e) => e.preventDefault();
    document.addEventListener('contextmenu', handler);
    return () => document.removeEventListener('contextmenu', handler);
  }, []);

  // Render bridges as SVG lines
  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges) {
      if (count === 0) continue;
      const [x1, y1, x2, y2] = key.split(',').map(Number);
      const px1 = x1 * GRID;
      const py1 = y1 * GRID;
      const px2 = x2 * GRID;
      const py2 = y2 * GRID;

      if (count === 1) {
        lines.push(
          <line key={key} x1={px1} y1={py1} x2={px2} y2={py2}
            stroke="#0f0" strokeWidth="2" />
        );
      } else if (count === 2) {
        const isHoriz = (y1 === y2);
        const offset = 4;
        if (isHoriz) {
          lines.push(
            <line key={key + '-a'} x1={px1} y1={py1 - offset} x2={px2} y2={py2 - offset}
              stroke="#0f0" strokeWidth="2" />
          );
          lines.push(
            <line key={key + '-b'} x1={px1} y1={py1 + offset} x2={px2} y2={py2 + offset}
              stroke="#0f0" strokeWidth="2" />
          );
        } else {
          lines.push(
            <line key={key + '-a'} x1={px1 - offset} y1={py1} x2={px2 - offset} y2={py2}
              stroke="#0f0" strokeWidth="2" />
          );
          lines.push(
            <line key={key + '-b'} x1={px1 + offset} y1={py1} x2={px2 + offset} y2={py2}
              stroke="#0f0" strokeWidth="2" />
          );
        }
      }
    }
    return lines;
  };

  // Render islands
  const renderIslands = () => {
    return islands.map(island => {
      const px = island.x * GRID;
      const py = island.y * GRID;
      const isSelected = selectedIsland && selectedIsland.id === island.id;

      return (
        <g key={island.id}
          onClick={(e) => handleIslandClick(island, e)}
          onContextMenu={(e) => handleIslandRightClick(island, e)}
          style={{ cursor: 'pointer' }}>
          <circle cx={px} cy={py} r={16}
            fill="black" stroke={isSelected ? '#ff0' : '#0f0'} strokeWidth="2" />
          <text x={px} y={py} textAnchor="middle" dominantBaseline="central"
            fill="#0f0" fontSize="14" fontFamily="monospace">
            {island.value}
          </text>
        </g>
      );
    });
  };

  // Render cursor (NOT a circle - use rect)
  const renderCursor = () => {
    const island = islands.find(i => i.id === cursorIslandId);
    if (!island) return null;
    const px = island.x * GRID;
    const py = island.y * GRID;
    return (
      <rect x={px - 20} y={py - 20} width={40} height={40}
        fill="none" stroke="#0f0" strokeWidth="2"
        strokeDasharray="4 2" opacity="0.8" />
    );
  };

  return (
    <div style={{ margin: 0, padding: 0 }}>
      <div style={{ padding: '10px', display: 'flex', gap: '10px', alignItems: 'center' }}>
        <select value={puzzleIndex} onChange={handlePuzzleChange}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}>
          {puzzles.map((p, i) => (
            <option key={p.id} value={i}>{p.name}</option>
          ))}
        </select>
        <button onClick={handleReset}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace', cursor: 'pointer' }}>
          Reset
        </button>
        {errorMsg && <span className="error-message" style={{ color: '#f00', fontFamily: 'monospace' }}>{errorMsg}</span>}
        {victory && <span className="victory-banner" style={{ color: '#0f0', fontFamily: 'monospace', fontSize: '20px' }}>SOLVED!</span>}
      </div>
      <svg width={800} height={600} style={{ display: 'block' }}>
        {renderBridges()}
        {renderIslands()}
        {renderCursor()}
      </svg>
    </div>
  );
}

export default App;
