  const resetPuzzle = useCallback(() => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMsg(null);
    setVictory(false);
  }, []);

  const handlePuzzleChange = (e) => {
    setPuzzleIndex(Number(e.target.value));
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMsg(null);
    setVictory(false);
  };

  const handleReset = () => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMsg(null);
    setVictory(false);
  };

