  const toggleBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const currentCount = bridges.get(key) || 0;

    if (currentCount === 0) {
      // Try to add single
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setErrorMsg(result.error);
        return;
      }
      const newBridges = new Map(bridges);
      newBridges.set(key, 1);
      setErrorMsg(null);
      setBridges(newBridges);
      const won = isVictory(islands, newBridges);
      setVictory(won);
    } else if (currentCount === 1) {
      // Try to add second
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setErrorMsg(result.error);
        return;
      }
      const newBridges = new Map(bridges);
      newBridges.set(key, 2);
      setErrorMsg(null);
      setBridges(newBridges);
      const won = isVictory(islands, newBridges);
      setVictory(won);
    } else {
      // Remove (double -> none)
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setErrorMsg(null);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges, islands]);

  // Remove bridge entirely
  const removeBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const currentCount = bridges.get(key) || 0;
    if (currentCount > 0) {
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setErrorMsg(null);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges]);

  // Handle island click
  const handleIslandClick = useCallback((island, e) => {
    if (e.ctrlKey || e.button === 2) {
      // Right-click or ctrl-click: remove bridge if selected
